public class CastingExample {
    public static void main(String[] args) {
        // Widening (implicit) — safe, automatic
        int num = 100;
        double bigNum = num;
        System.out.println("int to double: " + bigNum);

        // Narrowing (explicit) — can lose data!
        double pi = 3.14159;
        int roughPi = (int) pi;
        System.out.println("double to int: " + roughPi);

        // Literals
        int hex = 0xFF;        // hexadecimal
        int binary = 0b1010;   // binary
        char letter = 'A';     // char literal
        String text = "Hello"; // String literal

        System.out.println("Hex: " + hex);
        System.out.println("Binary: " + binary);
    }
}

