public class CastingPractice {
    public static void main(String[] args) {
        double decimal = 9.87;
        int truncated = (int) decimal;
        System.out.println("Double to int: " + truncated);

        int whole = 42;
        double widened = whole;
        System.out.println("Int to double: " + widened);
    }
}
